// @venom: browser
import React from "../jsx-runtime"; import type { ScoredIncident } from "../data/types"; import { age } from "../utils/format";
interface IncidentTableProps { incidents:ScoredIncident[]; limit?:number; onSelect:(id:string)=>void; }
export default function IncidentTable({incidents,limit=12,onSelect}:IncidentTableProps){ return <article className="panel table-panel"><div className="panel-heading"><div><p className="eyebrow">Prioritized by protected model</p><h2>Active incidents</h2></div><span className="count-pill">{incidents.length} records</span></div><div className="table-wrap"><table><thead><tr><th>Incident</th><th>Service</th><th>Region</th><th>Risk</th><th>Status</th><th>Owner</th><th>Age</th></tr></thead><tbody>{incidents.slice(0,limit).map(item=><tr onClick={()=>onSelect(item.id)}><td><strong>{item.id}</strong><span>{item.title}</span></td><td>{item.service}</td><td>{item.region}</td><td><span className={`risk-badge ${item.riskBand.toLowerCase()}`}>{item.riskScore} · {item.riskBand}</span></td><td><span className="status-badge">{item.status}</span></td><td>{item.owner}</td><td>{age(item.ageMinutes)}</td></tr>)}</tbody></table></div></article>; }
